INSERT INTO public.photos VALUES (25979, 'Plaza del Pilar 1974', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Setiembre 1974. Vista a├®rea, desde la altura de los tejados de las c├║pulas del Pilar, de la Plaza de las catedrales, la calle Alfonso, y la plaza del Gobierno Civil. A la derecha, la Seo y un fondo de cielo que deja ver, entre otros elementos, la Magdalena, el H├íbitat 2000, San Carlos Borromeo, San Pedro Nolasco, San Gil...', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65632400, -0.87877500, '0101000020E6100000575BB1BFEC1EECBF3ACAC16C02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15214570736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15214570736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15214570736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26039, 'Vista a├®rea del Pilar 1957', 'Vista a├®rea centrada en la plaza del Pilar. Al fondo, la margen izquierda del r├¡o Ebro. Abajo a la derecha, la torre de la Seo. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST├ôRICO', 41.65658000, -0.87874300, '0101000020E610000080D8D2A3A91EECBF959A3DD00AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31243176661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31243176661.webp', 'https://www.flickr.com/photos/zaragozaantigua/31243176661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26080, 'El Pilar 1938', 'Imagen capturada un d├¡a nublado desde un aeroplano modelo Heinkel 45-F 2 "Pavo" de la Legi├│n C├│ndor, radicado en el aer├│dromo Sanjurjo, en funciones de reconocimiento sobrevuela el casco antiguo de la ciudad y centra su objetivo fotogr├ífico en el templo del Pilar. En primer t├®rmino, desemboque de la calle de Alfonso I en la arbolada plaza del Pilar, donde destaca a la izquierda, tras el Retiro Alto, la gran casona que fuera palacio de los marqueses de Aytona o de Medinacelli. De fondo, el r├¡o Ebro, la arboleda de Macanaz y el Arrabal.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST├ôRICO', 41.65602400, -0.87926000, '0101000020E61000006DCA15DEE522ECBF10B22C98F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54188362826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54188362826.webp', 'https://www.flickr.com/photos/zaragozaantigua/54188362826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20902, 'Plaza del Pilar 1990', 'Vista de las cimentaciones y otras estructuras de un gran templo romano halladas en 1990 ante el Ayuntamiento, durante la remodelaci├│n de la plaza del Pilar. Era justa y necesaria su destrucci├│n, para poder excavar un gran aparcamiento subterr├íneo. Por ello, las autoridades ocultaron a la ciudadan├¡a el hallazgo. La prospecci├│n dur├│ del 14 de mayo al 1 de junio. Dos a├▒os despu├®s, un informe del arque├│logo Jos├® Delgado hizo p├║blica la jugarreta perpetrada por el alcalde Antonio Gonz├ílez Trivi├▒o y su equipo de presuntos corruptos del PSOE. Al fondo a la derecha, el edificio El Cicl├│n. En la imagen, restos de la cimentaci├│n y parte del p├│dium de un gran templo romano del siglo I, bastante alejado del Foro de Caesaraugusta, lo cual unido a que ten├¡a una orientaci├│n eje E-O (entrada por el este), har├¡a pensar en la posible convivencia de dos foros conectados. En el presente caso, posiblemente se trataba del templo tetr├ístilo de columnas corintias con acanaladuras que aparece en numerosas monedas acu├▒adas en Caesaraugusta.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65584400, -0.87765300, '0101000020E6100000AC8F87BEBB15ECBF90A339B2F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32273657101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32273657101.webp', 'https://www.flickr.com/photos/zaragozaantigua/32273657101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20975, 'Calle Don Jaime I 1857', '"Carrretera General de Barcelona. Proyecto de traves├¡a por la ciudad de Zaragoza", plano de Jos├® de Echeverr├¡a, 1857. El conjunto de calles estrechas que llevaban del Puente de Piedra al Coso Medio ten├¡a los d├¡as contados en 1857: fue el a├▒o en que se empez├│ a derribar para prolongar la calle de San Gil hasta el Ebro, con diferentes excusas, como la esgrimida como t├¡tulo de este plano. A partir de 1860, la v├¡a se denominar├¡a Don Jaime I, hasta hoy, que muchos zaragozanos la siguen llamando San Gil, siglo y medio despu├®s. Fuente: AMZ.', 1857, 1857, 1857, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65425200, -0.87761800, '0101000020E610000090300C587215ECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19880597199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19880597199.webp', 'https://www.flickr.com/photos/zaragozaantigua/19880597199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20996, 'Calle Mayor c.1855', '[Casa de Manuel Esmir en Zaragoza]. Dibujo realizado por Valent├¡n Carderera y Solano del patio interior de la casa de Manuel Esmir (posiblemente construida en los siglos XV-XVI), que era utilizada como mes├│n y posada de Santa Ana, en la calle Mayor. Esta casa fue derribada hacia 1862, y parece ser que algunas de sus columnas fueron reutilizadas en el palacio de los duques de Villahermosa en Pedrola, durante unas reformas. Fuente visual: Biblioteca Nacional de Espa├▒a, bdh.bne.es/ Signatura: DIB/18/1/7882', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65524800, -0.87910800, '0101000020E6100000ECDCB419A721ECBF7C629D2ADFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33944184106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33944184106.webp', 'https://www.flickr.com/photos/zaragozaantigua/33944184106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21077, 'Palacio de Osera 1871', '"Proyecto de reparaci├│n y decorado de la casa n┬║ 142 de la calle de la Manifestaci├│n, propiedad de D. Calisto Loubet", plano alzado de la fachada del antiguo palacio de Osera de Zaragoza, seg├║n proyecto del arquitecto Pedro Esteban y Romeo, 8 de agosto de 1871. En la imagen, a la izquierda, "Estado actual"; a la derecha, "Reforma". El de Osera es un ejemplo de palacio renacentista zaragozano desaparecido. Su acceso se encontraba a la altura del actual n├║mero 26 de la calle de Espoz y Mina, junto a la iglesia de Santa Cruz, con la que compart├¡a medianeras. Fue construido entre 1510 y 1515 como vivienda de Gaspar de Ari├▒o, familia que obtuvo el marquesado de Osera en 1634. Tras sucesivas reformas, como la de 1871, que modific├│ el aspecto de la tercera planta, fue derribado en 1963. Sus ├║ltimos usos lo asocian a Acci├│n Social Cat├│lica y la Caja de Ahorros de la Inmaculada, llegando a tener un amplio sal├│n de actos para representaciones teatrales en el gran espacio que ocupaba hacia la plaza de Santa Cruz. En las techumbres de sus salas principales contaba con ricos artesonados mud├®jares de madera, que fueron trasladados al Ayuntamiento de Zaragoza, terminado en 1965 en la Plaza del Pilar 18. Hoy contin├║an adornando el techo del Sal├│n de Sesiones, del Sal├│n de Comisiones y del despacho del Alcalde. Su patio principal est├í reconstruido mediante sus cuatro columnas originales en la antigua casa de GIl Gonz├ílez Marcilla, desde 1984 discoteca Torreluna. Fuente: "La casa de Gaspar de Ari├▒o y las techumbres mud├®jares de Zaragoza", Rafael Chiribay, DGA, 1999.', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65440400, -0.87803700, '0101000020E6100000C8B1F50CE118ECBF902FA182C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22181043502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22181043502.webp', 'https://www.flickr.com/photos/zaragozaantigua/22181043502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21143, 'Iglesia de Santiago c.1890', 'En la confluencia de las calles de la Cuchiller├¡a y Santiago se levantaba la iglesia de Santiago, de origen rom├ínico. All├¡ se reun├¡a el Concejo (Ayuntamiento) hasta la construcci├│n de las Casas de la Puente en el siglo XIII. Fue derribada entre 1911 y 1913. En el edificio actual, Don Jaime I 39, una Cruz de Santiago recuerda la ubicaci├│n y la fecha de la construcci├│n del inmueble construido en su lugar (1915-1916). La advocaci├│n al santo fue trasladada a la iglesia del antiguo convento de San Ildefonso. En la imagen se atisban restos del antiguo p├│rtico. Fuente visual: "Restos bizantinos (sic) de la iglesia de Santiago", fototipia de Joarizti y Mariezcurrena, en Zaragoza art├¡stica, monumental ├® hist├│rica, por A. y P. Gasc├│n de Gotor.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65469800, -0.87726900, '0101000020E61000008F6D19709612ECBFD960E124CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14906230637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14906230637.webp', 'https://www.flickr.com/photos/zaragozaantigua/14906230637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21298, 'Calle Santa Cruz 1903', '"Fachada de la Casa del Canal y oficinas de obras p├║blicas". Fotograf├¡a publicada con motivo de la visita a Zaragoza del rey Alfonso XIII, en octubre de 1903. Al fondo, casa Tar├¡n o del Canal. A la derecha, esquina del palacio de los Francos de Villalba, cuyo derribo dio lugar a la plaza de Santa Cruz. Fuente: Revista La Ilustraci├│n Espa├▒ola y Americana.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65428100, -0.87890800, '0101000020E6100000282B86AB0320ECBF74B2D47ABFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32356687532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32356687532.webp', 'https://www.flickr.com/photos/zaragozaantigua/32356687532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22460, 'Universidad 1960', 'Imagen a├®rea capturada sobre el entorno del despejado campus universitario de la plaza de San Francisco, con los pabellones de las facultades de Filosof├¡a y Letras, Ciencias, y Derecho, el Colegio Mayor Pedro Cerbuna, y la gran pista de atletismo, trazada sobre la antigua carretera de Valencia, que ahora se derivar├¡a por la nueva calle de Don Juan Bosco, a la izquierda. A la derecha, e inmediato, el cuartel de artiller├¡a de Palafox, cuya antigua pista de equitaci├│n todav├¡a aparece delimitada dentro del nuevo reciento universitario, y los dos grandes bloques de viviendas frente a los que se destacan las nuevas instalaciones de "La H├¡pica". Al fondo, y tras la Ciudad Jard├¡n, y las traseras de la calle de Corona de Arag├│n, la ciudad. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64036700, -0.90232200, '0101000020E610000011C30E63D2DFECBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31942081996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31942081996.webp', 'https://www.flickr.com/photos/zaragozaantigua/31942081996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21462, 'Calle de Espoz y Mina 1915', 'In├®dita imagen capturada desde la calle de Don Jaime I y orientada hacia el tramo final de la calle de Espoz y Mina que desemboca en ella. A la izquierda, el antiguo inmueble del n┬║ 46 que poco despu├®s ser├¡a derribado junto con la vecina gran casa que fuera del conde de Atar├®s y en cuyo solar ser├¡a construida la moderna casa de los Mar├¡n Corral├® proyectada por el arquitecto Francisco Albi├▒ana. En el n┬║ 36 se abre el ingreso principal a la gran casa de los Osera, y poco despu├®s destaca la sobria fachada de la neocl├ísica iglesia de la Santa Cruz, en el recoleto tramo de la calle donde confronta con la antigua casa de Aguilar o Pardo. A la derecha, traseras del palacio de Montemuzo y tras ellas los inmuebles de los n├║meros 35-41 que tiempo despu├®s ser├¡an retranqueados. La circulaci├│n rodada se presenta en el formato de carro a tracci├│n de sangre, mientras una caballer├¡a montada se encamina a Don Jaime I, donde en primer t├®rmino y entre el adoquinado destacan las v├¡as por las que transitan los coches de las l├¡neas Arrabal y G├íllego.', 1915, 1915, 1915, 'Anos 10', 'CASCO HIST├ôRICO', 41.65432400, -0.87773600, '0101000020E61000000BB3D0CE6916ECBF747E8AE3C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52428359237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52428359237.webp', 'https://www.flickr.com/photos/zaragozaantigua/52428359237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21473, 'Don Jaime I 1917', 'Imagen capturada durante la construcci├│n del esquinero inmueble que ocupa el solar de los n├║meros 47-49 de la calle de Don Jaime I y los n├║meros 44-46 de la calle de Espoz y Mina (numeraci├│n luego modificada). Fue proyectado en 1916 por el arquitecto (y en ese momento tambi├®n concejal republicano) Francisco Albi├▒ana Corral├® para los doctores ├üngel y V├¡ctor Mar├¡n Corral├®, que lo destinaron al alquiler de viviendas y tiendas, reserv├índose la planta noble donde habilitar consulta profesional. El antiguo inmueble (gran casona que fuera del conde de Atar├®s) fue desalojado de sus inquilinos y autorizado a ser derribado a finales de 1916, coincidiendo en el tiempo con la finalizaci├│n del derribo de la vecina iglesia de Santiago. Al fondo de la imagen, medianera con el colindante edificio del n├║mero 42 de la calle de Espoz y Mina.', 1917, 1917, 1917, 'Anos 10', 'CASCO HIST├ôRICO', 41.65426000, -0.87767200, '0101000020E61000005CAD1397E315ECBF5D8AABCABED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54167493986.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54167493986.webp', 'https://www.flickr.com/photos/zaragozaantigua/54167493986/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21527, 'Casa de los Tar├¡n c.1924', 'La parroquia de la Exaltaci├│n de la Santa Cruz ten├¡a un car├ícter estamentalmente muy exclusivo y nobiliario. En su jurisdicci├│n se levantaron una notable cantidad de palacios y casas solariegas, como la de la familia de los Tar├¡n, que provey├│ al Reino de hasta dos medievales Justicias. En el siglo XVI esta familia levant├│ una gran casa seg├║n las formas y maneras de la italiana moda renacentista, centrando la construcci├│n en torno a un gran patio al que se acced├¡a desde la calle por un portal├│n que permit├¡a el paso a caballer├¡as y carruajes. Este edificio fue luego remodelado intensamente, en varias ocasiones. En 1706 devino en sede del Tribunal de la Santa Inquisici├│n, cuando ├®sta fue desahuciada de la Aljafer├¡a por el borb├│n Felipe. Aqu├¡ estuvo hasta 1759. Unos pocos a├▒os despu├®s, en 1765, la Casa fue reformada en las formas dieciochescas del momento: su fachada fue enfoscada, y se abri├│ una segunda puerta de acceso, en piedra, y formas netamente neocl├ísicas. En la imagen, detalle de esta puerta. Fuente visual: "Una mirada a trav├®s de la arquitectura: Regino y Jos├® Borobio Ojeda", Daniel Estab├®n Boldova.', 1924, 1924, 1924, 'Anos 20', 'CASCO HIST├ôRICO', 41.65422200, -0.87871700, '0101000020E6100000300E2E1D731EECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17126822342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17126822342.webp', 'https://www.flickr.com/photos/zaragozaantigua/17126822342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21556, 'Calle Jord├ín de Urri├®s 1929', 'Acto oficial de descubrimiento de la l├ípida que daba el nombre del fallecido capit├ín de Regulares de Ceuta, Ram├│n Jord├ín de Urri├®s, a la antigua calle del Clavel. Hijo del marqu├®s de Velilla de Ebro, en 1924 fue herido en los combates de la posici├│n de Coba-Darsa, durante la guerra colonial en el Protectorado de Marruecos, y muri├│ a los pocos d├¡as. Este homenaje se produc├¡a en los ├║ltimos momentos de la Dictadura de Primo de Rivera, m├ís de cinco a├▒os despu├®s de los hechos referidos. Fuente visual: "Mundo Gr├ífico" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65466800, -0.87720100, '0101000020E61000008597E0D40712ECBF6EDE3829CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21406598513.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21406598513.webp', 'https://www.flickr.com/photos/zaragozaantigua/21406598513/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21560, 'Arco de los Cartujos 1929', '"Zaragoza. Arco de los Cartujos. Estilo: Ojival [o G├│tico]". Imagen del antiguo arco de los Cartujos desde la calle Bayeu, en el tramo entre Goicoechea (a la espalda), y Santiago (delante). Al fondo, la calle de Espoz y Mina. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65518400, -0.87815400, '0101000020E61000002D40DB6AD619ECBF656EBE11DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22358490544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22358490544.webp', 'https://www.flickr.com/photos/zaragozaantigua/22358490544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21615, 'Espoz y Mina 1921', 'Con la venia y bendici├│n del cardenal-arzobispo Juan Soldevila y Romero, fue organizada en Zaragoza la asamblea general del partido carlista-jaimista (por Jaime de Borb├│n y Borb├│n-Parma, pretendiente carlista al trono de Espa├▒a) Comuni├│n Tradicionalista. Efectivamente, el primer acto del programa fue una tradicional misa y comuni├│n general en el Pilar, que dio paso a tres intensos d├¡as de discusiones pol├¡ticas en la sede del C├¡rculo Jaimista local, en la calle Espoz y Mina. En la imagen, un grupo de asamble├¡stas posa tras las autoridades (terrenales) del partido, encabezadas por el secretario pol├¡tico Jos├® Selva Mergelina, marqu├®s de Villores, en el patio trasero de la sede Jaimista, un d├¡a de sol, y buen tiempo. Fuente visual: foto Miguel Mar├¡n Chivite, en revista "La Hormiga de Oro".', 1921, 1921, 1921, 'Anos 20', 'CASCO HIST├ôRICO', 41.65505600, -0.87946200, '0101000020E61000005E64027E8D24ECBF388600E0D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31798357243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31798357243.webp', 'https://www.flickr.com/photos/zaragozaantigua/31798357243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21638, 'Calle de San Voto c.1922', 'Imagen del patio central de la gran casa del siglo XVII esquinera entre las calles de San F├®lix y San Voto, reci├®n reformada por Pascual Bravo Sanfeliu para habilitarla como sede del Sindicato Central de Arag├│n. El chorro de luz natural que entra por el patio ilumina cenitalmente la oficina de atenci├│n al p├║blico instalada en ├®l.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65396400, -0.87868000, '0101000020E6100000E7C6F484251EECBF7461A417B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50826773013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50826773013.webp', 'https://www.flickr.com/photos/zaragozaantigua/50826773013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21670, 'Vista parcial c.1932', 'Foto a├®rea del Pilar y su entorno.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65569200, -0.87928300, '0101000020E610000078B81D1A1623ECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728687219.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728687219.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728687219/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22525, 'Pol├¡gono Romareda 1970', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/setiembre 1970. El "Plan Parcial de la Gran V├¡a" (1961) estaba cobrando forma a pocos metros del campo municipal de la Romareda. Promovido por el Ministerio de la Vivienda, actuaba sobre 29 hect├íreas, en las que levantar 2224 viviendas agrupadas en cooperativas de funcionarios y empleados, como "Santa Rita", "Peritos Industriales", "San Crist├│bal", "Espejo de Justicia"... as├¡ hasta 33. Junto con las viviendas, estaban previstas zonas verdes y todos los servicios posibles. En cuanto al nombre del pol├¡gono, en principio estaba previsto "Barrio de la Paz", aunque oficialmente su etiqueta era "Pol├¡gono Gran V├¡a". Pues ni una cosa ni otra, porque ya en Torrero exist├¡a la barriada de la Paz (modesta, pero digna), y la Gran V├¡a conservaba reminiscencias de m├ís poder├¡o econ├│mico. Terminar├í adoptando, por extensi├│n, el de la acequia que por estos lares flu├¡a de antiguo: Romareda. En la imagen, tomada desde las alturas del n┬║ 5 de la calle S. Francisco de Borja (1962), una panor├ímica de buena parte del Pol├¡gono Romareda, en pleno frenes├¡ constructivo. De momento, hormig├│n, acero, ladrillos, y mucha mano de obra. Luego vendr├ín las calles: Violante de Hungr├¡a (en primer├¡simo plano, de izquierda a derecha), As├¡n y Palacios (justo enfrente), Luis Bermejo (el camino a mitad de imagen, de izquierda a derecha), Pedro III el Grande (paralelo, m├ís hacia el fondo), Condes de Arag├│n (derecha)... A la izquierda queda el recinto de la Feria de Zaragoza y el estadio Municipal de la Romareda. A la derecha, el solar donde se construir├í el Palacio de Deportes de Zaragoza, o "El Huevo". Las instalaciones educativas (p├║blicas y privadas) se ir├ín encajando en los huecos, como la parroquia de Sta. M├│nica (1972). En cuanto a las zonas verdes, pues mejor ir al Parque Grande, que est├í bien cerca.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63954900, -0.90196200, '0101000020E610000017838769DFDCECBF4298DBBDDCD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665456160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665456160.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665456160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21857, 'Plza. San Braulio 1934', 'Imagen capturada en la angosta plazuela de San Braulio con motivo de la nocturna explosi├│n de un artefacto durante la huelga general de treinta y cinco d├¡as entre los meses de abril-mayo de ese a├▒o. El explosivo fue colocado junto al economato de consumo Cooperativa Militar y Civil, moderna construcci├│n de 1931 sita a la izquierda de la imagen, edificio que perdura. Una pareja que casualmente sali├│ de una vivienda de la calle Miguel de Molino, al fondo a la derecha, result├│ levemente afectada, as├¡ como los cristales de las ventanas traseras de la gran sede de Comuni├│n Tradicionalista en la calle de Espoz y Mina (a la derecha), que fuera sede local del carlista C├¡rculo Jaimista. El edificio objeto del atentado apenas sufri├│ da├▒os. En la imagen, fuerza del cuerpo de Seguridad y Asalto, y de la polic├¡a, inspeccionan la zona y miran al reportero gr├ífico. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65481500, -0.87944100, '0101000020E6100000815EB8736124ECBF12F758FAD0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36108423460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36108423460.webp', 'https://www.flickr.com/photos/zaragozaantigua/36108423460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21921, 'Calle de Espoz y Mina 1939', 'Imagen capturada durante la matinal del ├║ltimo d├¡a del "A├▒o de la Victoria" en la calle de Espoz y Mina a la altura de la parroquia de Santa Cruz (a la izquierda y fuera de plano), al paso de la gran cabalgata anunciadora de las fiestas del "XIX Centenario de la venida de la Virgen en carne mortal (sic) a Zaragoza". A la derecha y esquinera con la calle de Francisco Bayeu, la antigua casa del infanz├│n Jer├│nimo C├│sida habilitada para albergar los muebleros Almacenes Moliner.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65454100, -0.87811200, '0101000020E6100000723447567E19ECBF1172DEFFC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54241826916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54241826916.webp', 'https://www.flickr.com/photos/zaragozaantigua/54241826916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21929, 'Nevada plaza de La Seo c.1944', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. (SF). Imagen de la Plaza del Pilar y de la Plaza de la Seo, tras una fuerte nevada.', 1944, 1944, 1944, 'Anos 40', 'CASCO HIST├ôRICO', 41.65558300, -0.87724300, '0101000020E610000040A374E95F12ECBF2368CC24EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14904139066.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14904139066.webp', 'https://www.flickr.com/photos/zaragozaantigua/14904139066/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22042, 'Casimiro Morcillo 1955', 'Foto Luis Mompel. El 5 de diciembre de 1955, Casimiro Morcillo pasea en mula por la plaza del Pilar, con la Seo al fondo y el Gobierno Civil a la derecha. Es su presentaci├│n como nuevo arzobispo, tras la muerte de su predecesor, Rigoberto Dom├®nech. Dur├│ en su cargo hasta 1964, cuando fue llamado a presidir la nueva archidi├│cesis de Madrid, nada menos. Hasta lleg├│ a ser presidente de la Conferencia Episcopal. Le sucedi├│ Pedro Cantero Cuadrado.', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65574300, -0.87804900, '0101000020E6100000D9226937FA18ECBF5CCAF962EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750529500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750529500.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750529500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22189, 'Calle de Alfonso I c.1950', 'Grandes almacenes textiles y de peleter├¡a La Campana de Oro, ubicados en la achaflanada esquina entre la calle de Alfonso I con la de Prudencio, a la izquierda, abiertos en 1885 y clausurados en 2013. Como ilustra la imagen, el car├ícter comercial de esta calle ven├¡a determinado, adem├ís de por las tiendas en planta calle, por las ubicadas en los pisos superiores.', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST├ôRICO', 41.65580400, -0.87956200, '0101000020E610000040BD19355F25ECBF024BAE62F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32210891574.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32210891574.webp', 'https://www.flickr.com/photos/zaragozaantigua/32210891574/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22293, 'Pl. del Pilar 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 08/12/1965. "Cuerpo de Infanter├¡a celebra la fiesta de la Inmaculada." Entre los actos festivos y celebraciones varias organizadas con motivo de la inauguraci├│n de la nueva Casa Consistorial de la plaza del Pilar, se incluyeron tambi├®n algunas actuaciones castrenses de recia virilidad y bravo ardor patrio. En la imagen, el ├üngel Custodio, San Valero, y autoridades militares y civiles, en uno de los desfiles de ese a├▒o, ante la puerta del Ayuntamiento. Quienes mejor se lo estaban pasando eran las se├▒oras de la derecha extrema.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65587900, -0.87743600, '0101000020E610000065A88AA9F413ECBF0C91D3D7F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15358580566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15358580566.webp', 'https://www.flickr.com/photos/zaragozaantigua/15358580566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22349, 'Guardias c.1968', 'Foto ├üngel Duerto. Grupo de guardias de tr├ífico de la polic├¡a municipal de Zaragoza, ante el Ayuntamiento. Fuente: "El municipio en Arag├│n", DPZ, 2004.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65588700, -0.87781100, '0101000020E6100000B53522180717ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20354555718.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20354555718.webp', 'https://www.flickr.com/photos/zaragozaantigua/20354555718/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22668, 'Calle San F├®lix 1973', 'Calle de San F├®lix. Al fondo, el antiguo palacio de los Torrero y la calle de San Voto. A la derecha, muro que se├▒ala el derribo del palacio de Ari├▒o. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65385800, -0.87855300, '0101000020E61000009FAF592E1B1DECBF2E1D739EB1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23117995416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23117995416.webp', 'https://www.flickr.com/photos/zaragozaantigua/23117995416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22669, 'Calle San Voto 1973', 'Calle San Voto. En el centro, su entrada al palacio de los Torrero. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65393000, -0.87825200, '0101000020E6100000E2B034F0A31AECBFC8EF6DFAB3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23180093591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23180093591.webp', 'https://www.flickr.com/photos/zaragozaantigua/23180093591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22684, 'Calle de San Voto 1972', 'Imagen capturada en la plaza de Santa Cruz y centrada en el tramo de los pares de la calle de San Voto (antigua del Correo Viejo): de derecha a izquierda, los inmuebles de los n├║meros 2, 4 y el 6-8, antiguo gran caser├│n que alberg├│ el denominado "Hogar del Herido" creado por la Falange Espa├▒ola Tradicionalista que conservaba junto a su ingreso una l├ípida con inscripci├│n que informaba del car├ícter de la inmediata "Glorieta de la Santa Cruz" como "s├¡mbolo de la nueva Espa├▒a, de nuestra Patria cristiana que resurge teniendo por gu├¡a la Santa Cruz", y que conclu├¡a con las rituales exclamaciones "┬íArriba Espa├▒a! ┬íViva Espa├▒a!" Al fondo, traseras de la gran casona del n┬║ 31 de la calle de Don Jaime I, poco antes de su derribo que permitir├¡a duplicar el espacio de la recoleta plaza de Ari├▒o (antigua plazuela de San Mart├¡n y Atar├®s) . Los referidos n├║meros 2 y 4 de San Voto tambi├®n ser├¡an derribados a├▒os despu├®s, sustituidos por modernos inmuebles. Fuente visual: AMZ.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65404600, -0.87873300, '0101000020E61000009C4F1DAB941EECBF310A82C7B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26718541287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26718541287.webp', 'https://www.flickr.com/photos/zaragozaantigua/26718541287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22722, 'Museo Cam├│n Aznar 1979', 'Imagen de la renacentista casa de los C├│sida y Albi├│n en la antigua Calle Mayor que, tras numerosos avatares y usos polifac├®ticos (incluso como Capitan├¡a General), a mediados de los a├▒os 70 del siglo XX, camino de su aniversario 450, fue adquirida por una poderosa entidad local de ahorro. Rehabilitada bajo direcci├│n de Regino Borobio, en 1979 fue abierta como "Museo de Humanidades Cam├│n Aznar", para albergar las colecciones de arte donadas por el matrimonio Jos├® Cam├│n Aznar-Mar├¡a Luisa ├ülvarez. En la imagen, estado del restaurado patio y de la escalera de acceso a los pisos superiores, un poco antes de su apertura p├║blica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65478000, -0.87829500, '0101000020E6100000B4B0A71DFE1AECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30304382276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30304382276.webp', 'https://www.flickr.com/photos/zaragozaantigua/30304382276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22754, 'Polic├¡a motorizada 1977', 'Presentaci├│n de la unidad motorista de la Polic├¡a Municipal, ante el Ayuntamiento, en la celebraci├│n de Nuestra Se├▒ora del Portillo. Al fondo, entre brumas, la torre de la Seo. Fuente: Heraldo.es', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65583300, -0.87781600, '0101000020E610000027FA7C941117ECBF9C51F355F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32696414290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32696414290.webp', 'https://www.flickr.com/photos/zaragozaantigua/32696414290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22839, 'Salchichauto c.1981', 'En la furgoneta de la imagen, una DKW modelo "Veh├¡culo tienda" matriculada en 1946, conocida como "Salchichauto", F├®lix Hern├índez Gonz├ílez vend├¡a bocadillos de salchicha, refrescos y cervezas en la plaza del Pilar, junto al Gobierno civil, desde 1971. Esta tienda ambulante se trasladaba a diversas ubicaciones en funci├│n de las posibilidades de negocio, como las ferias, la plaza de toros o el entorno de La Romareda, cuando all├¡ se celebraban las pruebas pr├ícticas de los ex├ímenes de conducir y los copazos de co├▒ac y de "revueltillo" daban ├ínimos extra a los examinandos.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.65540000, -0.87825900, '0101000020E6100000815D4D9EB21AECBF32E6AE25E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14896793825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14896793825.webp', 'https://www.flickr.com/photos/zaragozaantigua/14896793825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22865, 'Plaza de Santa Cruz 1987', 'Luis M├¡nguez. 1987. Verde imagen de una plaza regida por la Cruz de hierro de Regino Borobio inaugurada en mayo de 1937, con la inscripci├│n ÔÇ£TRANSEUNTE. ESTA CRUZ BENDITA ESPERA DE TI UNA ORACION POR LOS MARTIRES DE LA GUERRA R.I.P.ÔÇØ A la izquierda, la "Casa del Canal", o Casa Tar├¡n. A la derecha, las traseras de la iglesia de la Exaltaci├│n de la Santa Cruz, con visual parcial de su torre. La plaza se llama de la Santa Cruz, por si acaso.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65422200, -0.87871700, '0101000020E6100000300E2E1D731EECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15665916418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15665916418.webp', 'https://www.flickr.com/photos/zaragozaantigua/15665916418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22880, 'M├ís Birras a├▒os 80', 'Foto: Vicente Morcano, a├▒os 80 del siglo XX. Instant├ínea del grupo de rock zaragozano M├ís Birras (1985-1993) haciendo honor a su nombre. Su cantante, Mauricio Aznar (a la derecha) continu├│ su carrera musical en solitario hasta su muerte en 2000. El Ayuntamiento le dedic├│ una calle en el barrio de Casablanca. La foto est├í tomada en la plaza del Pilar de Zaragoza, frente al Ayuntamiento. En 2015 hay all├¡ un solar. Fuente: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1980, 1980, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65522700, -0.87839700, '0101000020E6100000C3F17C06D41BECBF643A747ADED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19298298371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19298298371.webp', 'https://www.flickr.com/photos/zaragozaantigua/19298298371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22948, 'Calle de Santiago 1985', 'Imagen parcial de la fachada de la gran casa del siglo XVI localizada en la calle de Santiago e inmediata a la iglesia hom├│nima, que a principios del siglo XIX hab├¡a recaido en el marquesado de Montemuzo. Deshabitado y abandonado largo tiempo, a finales de 1984 el ayuntamiento acometi├│ obras de consolidaci├│n tras el hundimiento de la zona central y patio de la casa. La captura se corresponde con el resultado del apuntalamiento de la gran puerta de ingreso. A la derecha, el moderno edificio del n├║mero 30-32 de la calle. En la primavera de 1985 la familia Latorre Montalvo, heredera patrimonial del inmueble, vendi├│ el edificio al ayuntamiento, que tras una importante intervenci├│n lo destin├│ a sede del Archivo, Biblioteca y Hemeroteca municipales. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST├ôRICO', 41.65492800, -0.87759600, '0101000020E61000009C36E3344415ECBF0A9E42AED4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38643880244.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38643880244.webp', 'https://www.flickr.com/photos/zaragozaantigua/38643880244/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22996, 'Pasaje El Cicl├│n 1992', 'Imagen capturada en el interior del Pasaje del Comercio y de la Industria, realizado en 1882-1883 con dise├▒o del arquitecto Fernando de Yarza como galer├¡a comercial en los bajos de la nueva manzana de viviendas delimitada por las calles de Alfonso I, plaza del Pilar, calle de Forment y de Santiago. La influencia est├®tica francesa de la ├®poca (Segundo Imperio) queda fijada mediante formas ecl├®cticas y configura uno de los m├ís castizos espacios comerciales de la ciudad, tambi├®n denominado "El Cicl├│n" por los referenciales almacenes de la derecha. En 1998 fue restaurado y rehabilitado, y en 2008 inici├│ un proceso de revitalizaci├│n que contin├║a, rompiendo as├¡ la tendencia de lo sucedido con tantos otros pasajes comerciales por su extrema y desconsiderada cercan├¡a a la ciudad consolidada. La de la imagen es la galer├¡a comercial a la que se ingresa desde la calle de Santiago (al fondo) pasando bajo un forjado arco con la leyenda "Pasaje del Comercio". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1992, 1992, 1992, 'Anos 90', 'CASCO HIST├ôRICO', 41.65558500, -0.87887200, '0101000020E6100000F5D72B2CB81FECBFC45F9335EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23930140657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23930140657.webp', 'https://www.flickr.com/photos/zaragozaantigua/23930140657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23031, 'Plaza de Ari├▒o 1992', 'Plaza de Ari├▒o, en una vista tomada desde la calle de Don Jaime I. Al fondo, calle de San Voto, con el palacio renacentista de los Torrero, del siglo XVI, que alberga el Colegio de Arquitectos. A la derecha, sede de una entidad bancaria. En primer plano, fuente minimalista de hormig├│n, en la l├¡nea de las llamadas ÔÇ£plazas durasÔÇØ de la ├®poca. El aspecto de la plaza fue configurado as├¡ en 1990. En 1996 se a├▒adi├│ al entorno una estatua de bronce, obra de Manuel Arc├│n, representando a Eduardo Jimeno Correas, uno de los pioneros del cine espa├▒ol.', 1992, 1992, 1992, 'Anos 90', 'CASCO HIST├ôRICO', 41.65381000, -0.87818700, '0101000020E61000001CB7989F1B1AECBF1DE6CB0BB0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207283017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207283017.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207283017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23070, 'Casa Tar├¡n 2007', 'Aspecto de la Casa Tar├¡n o del Canal Imperial, en la plaza de Santa Cruz 19 en 2007, antes de su restauraci├│n en 2009. Fuente: Wikipedia.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65437700, -0.87882800, '0101000020E61000000DE4D9E55B1FECBF962023A0C2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012098318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012098318.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012098318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23091, 'Plaza del Pilar 2000', 'Foto: Rogelio Allepuz, 8 de octubre de 2000. Despliegue de una gran bandera de Arag├│n en la plaza del Pilar, el domingo 8 de octubre, al finalizar la manifestaci├│n contra el Plan Hidrol├│gico Nacional, que inclu├¡a el trasvase del Ebro. Este vistoso ritual ven├¡a practic├índose, en el mismo entorno, desde 1993, con similares reivindicaciones. A la derecha, el Ayuntamiento luce engalanado por las Fiestas del Pilar, durante las que se celebr├│ el acto, respaldado por el alcalde Jos├® Atar├®s. Fuente: www.aparagon.org/fotoperiodistas/rogelio-allepuz/', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65580600, -0.87756600, '0101000020E6100000F19BC24A0515ECBFA2427573F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20343691156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20343691156.webp', 'https://www.flickr.com/photos/zaragozaantigua/20343691156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23157, 'Plaza del Pilar 2009', 'Dibujo de Lina Vila que representa una plaza del Pilar convertida en Venecia, merced a su inundaci├│n. Al fondo, el Ayuntamiento y la Lonja. Fuente: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65584400, -0.87769600, '0101000020E61000007E8FFAEB1516ECBF90A339B2F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32427969364.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32427969364.webp', 'https://www.flickr.com/photos/zaragozaantigua/32427969364/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23181, 'Calle de San Braulio c.2000', 'Ilustraci├│n centrada en el inmueble de la calle de San Braulio 5, construido en 1931 para sede de la Cooperativa Militar y Civil. Tras ser la sede del PSOE durante los a├▒os noventa, fue remodelado, junto al n├║mero 7 (que en la imagen luce un mural paisaj├¡stico), para albergar el centro Joaqu├¡n Roncal de la Funcaci├│n CAI y Acci├│n Social Cat├│lica, inaugurado en 2005. Fuente visual: "Centro Joaqu├¡n Roncal en Zaragoza", La Cadiera, 2006.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65481800, -0.87946400, '0101000020E61000008C4CC0AF9124ECBF836A8313D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41410463091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41410463091.webp', 'https://www.flickr.com/photos/zaragozaantigua/41410463091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23206, 'Plaza del Pilar 2010', 'Foto: Toni Gal├ín. Marquesina en la plaza del Pilar, frente al Ayuntamiento, en mayo de 2010. Arriba, protesta de la Asociaci├│n de Vecinos de La Madalena, por el deficiente arreglo del parque Bruil, con un mill├│n de euros procedentes del Plan E. Abajo, publicidad de la candidatura de Zaragoza a Capital Europea de la Cultura 2016. Compet├¡a desde 2009 con otras 14 ciudades, que quedaron en seis en un segundo corte, con Segovia, Burgos, C├│rdoba, Las Palmas de Gran Canaria y San Sebasti├ín, que result├│ elegida en 2011. Fuente: Heraldo de Arag├│n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65575600, -0.87818900, '0101000020E6100000499F56D11F1AECBFF01307D0EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32794799693.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32794799693.webp', 'https://www.flickr.com/photos/zaragozaantigua/32794799693/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23217, 'Plaza del Pilar 2016', 'Imagen lateral de la placa que recuerda a los 15 ediles republicanos y a los 30 trabajadores municipales asesinados por los sublevados en julio de 1936 contra la rep├║blica democr├ítica de Espa├▒a. 80 a├▒os despu├®s de los hechos, de ellos 37 tras la recuperaci├│n de la democracia municipal, y estando al alcald├¡a en manos de Zaragoza en Com├║n, el viernes 30 de septiembre de 2016 fue inaugurado este memorial instalado en la esquina de la fachada principal del Ayuntamiento con la calle de Xim├®nez de Emb├║n (a la derecha). En la imagen, obtenida con el punto de vista dirigido hacia el oeste de la plaza, la placa todav├¡a est├í cubierta por la tela que poco despu├®s ser├¡a retirada durante la inauguraci├│n, en la que estuvieron presentes todos los grupos pol├¡ticos con representaci├│n municipal en aquella ├®poca. La placa presenta un texto que dice: "A la memoria de los cargos electos y empleados municipales del Ayuntamiento de Zaragoza asesinados tras el golpe militar de julio de 1936 contra la legalidad constitucional de la Segunda Rep├║blica". Le sigue la relaci├│n de nombres y apellidos de los 15 ediles, entre ellos cinco alcaldes ped├íneos, y los 30 trabajadores municipales referidos. En la parte inferior, el escudo institucional del Ayuntamiento de Zaragoza.', 2016, 2016, 2016, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65585500, -0.87715700, '0101000020E61000009CA38E8EAB11ECBF84F57F0EF3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49980543982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49980543982.webp', 'https://www.flickr.com/photos/zaragozaantigua/49980543982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23246, 'Saraqusta 1118', 'Recreaci├│n de Saraqusta y su entorno m├ís inmediato en una vista a├®rea sobre, en primer t├®rmino, al-Jazir├ñ/la Isla, donde Abderram├ín III acamp├│ en 937 para asediar la ciudad, porque resulta complicado asediarla desde un enclave situado a 7 kil├│metros en direcci├│n noroeste, como algunos opinantes atribuyen al entorno del castillo de Miranda.. El de la izquierda ser├¡a el brazo del r├¡o que siglos despu├®s, progresivamente desecado, dar├¡a lugar a las Balsas de Ebro Viejo. Al otro lado de este brazo fluvial, el arrabal de -ad-Dabbaj├¡n/de los Curtidores, luego de Altab├ís, donde se bifurcan los caminos hacia Jaqath/Jaca, al norte, y Ifr├íg├ñ/Fraga, al este. Tras cruzar el nahr Ibruh/r├¡o Ebro por al-Qantarath/el puente y rodeada por la muralla romana de piedra, recompuesta y reforzada varias veces, el per├¡metro de la madin├ñ/ciudad de Saraqusta. Entrando por b├íb al-Qantarath/Puerta de Alc├íntara o del puente, el -qasr qadim-/alcazar antiguo, la mezquita aljama y el barrio moz├írabe con la iglesia de Santa Mar├¡a Virgen. Destacan a la izquierda la zona de b├íb al-Qibla/puerta de la Qibla, actual Magdalena, junto al cementerio hom├│nimo, y a la derecha ┬┐al-kunna?/luego Torre Nueva, probable torre conmemorativa. En la esquina fluvial inferior destaca as-sudd├ñ/la Zuda, y b├íb al-Qal''├ñ/Puerta Beikala o del Castillo, por la que se acced├¡a a al-Mus├ír├ñ/La Almozara. Aqu├¡ estaba uno de los tres cementerios de la ciudad y el mausoleo de los ┬┐Ban├╝ Tuj├»b?, donde la actual torre de San Pablo, la m├ís antigua de las torres conservadas. Tras la muralla de la medina estaban los arrabales, protegidos por una muralla de mard├║m├ñ-/tapial. Por la b├íb Qala''├ñ Ayy├║b-/puerta de Calatayud, luego denominada de Sancho, se llegaba a -qasr al-Ja''afariyy├ñ-/palacio de La Aljafer├¡a. Paralela y entre los caminos a Tutilah/Tudela y Qal''ath Ayy├║b/Calatayud, la ass├íqya al-Mus├ír├ñ/acequia de La Almozara. Otras puertas de los arrabales eran las de b├íb Baltash/Baltax/luego del Carmen y -b├íb al-Yah├║d├¡n-/de los Jud├¡os, luego Pue', 1118, 1118, 1118, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65431600, -0.87852000, '0101000020E6100000B0389CF9D51CECBFF19F6EA0C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49830304073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49830304073.webp', 'https://www.flickr.com/photos/zaragozaantigua/49830304073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23305, 'Calle Alfonso 1960', 'Vista del Pilar desde la calle de Alfonso I. Fuente: Ajuntament de Girona. CRDI (Mart├¡ Massafont Costals).', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65569200, -0.87957100, '0101000020E61000000D52F0147225ECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26243291689.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26243291689.webp', 'https://www.flickr.com/photos/zaragozaantigua/26243291689/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23308, 'Calle de Alfonso I 1899', 'Interesante imagen capturada en la calle de Alfonso I a la altura del chaflanero desemboque de la calle de Prudencio (antigua de la Concepci├│n), donde destaca el comercio de Tejidos Soteras. Detr├ís de ella, la tambi├®n chaflanera terminaci├│n de la calle de la Manifestaci├│n (antigua de la Plater├¡a). La estampa incluye una antropol├│gica y plural galer├¡a de peatones, vendedora callejera ensillada (aprovechando la potencial clientela bajando hacia el templo del Pilar), c├ínido despavorido, y seg├║n nuestro experto en autom├│viles, monsieur Pierre Nodoyuna, posiblemente una "Voiturette" salida de los talleres de Alexis Vivinus en B├®lgica, o tal vez la versi├│n de este modelo construida bajo licencia por Georges Richard en Francia. Fuente visual: foto Francisco Garzar├ín, en Heraldo de Arag├│n.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65569200, -0.87957100, '0101000020E61000000D52F0147225ECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29891168777.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29891168777.webp', 'https://www.flickr.com/photos/zaragozaantigua/29891168777/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23793, 'Templete 1987', '1987. Huelga universitaria. Los alumnos de Filosof├¡a, posando ante el templete de la Oficina de Turismo que se alzaba en la zona del Gobierno Civil de la plaza del Pilar. Arquitectura posmoderna, rememorando el templo romano cuya estructura qued├│ destruida al construirse los garajes subterr├íneos que est├ín justo debajo. Fuente: Zaragozarebelde.org', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65575100, -0.87806900, '0101000020E6100000A034D4282419ECBFDFA815A6EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822216340.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822216340.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822216340/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23800, 'Plaza del Pilar 1982', 'Plaza del Pilar en 1982. Bas├¡lica, Ayuntamiento, Lonja, Monumento a Goya. Fuente: www.facebook.com/photo.php?fbid=1566597226901841&set=...', 1982, 1982, 1982, 'Anos 80', 'CASCO HIST├ôRICO', 41.65580100, -0.87766900, '0101000020E610000018D1764CDD15ECBF90D78349F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15021509019.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15021509019.webp', 'https://www.flickr.com/photos/zaragozaantigua/15021509019/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23807, 'Fraga Iribarne 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 28/02/1965. "Visita del ministro de Informaci├│n y Turismo Manuel Fraga Iribarne." Las fiestas del Pilar eran declaradas de "inter├®s tur├¡stico nacional", como una iniciativa m├ís de los planes de desarrollo impulsados por los tecn├│cratas del Opus Dei. La orientaci├│n del r├®gimen por el turismo incluy├│ una especial atenci├│n al "turismo religioso", mediante la creaci├│n de instituciones tur├¡sticas cat├│licas, un plan de apostolado para atender a turistas, y un cuerpo interdiocesano de capellanes del turismo que hablaran lenguas extranjeras. Adem├ís, se ofrecer├¡an misas en lenguas foranas, peregrinaciones por grupos ling├╝├¡sticos, y se establecer├¡an normas de "decencia" para el acceso de mujeres extranjeras a los templos (en verano, para evitar la lujuria). En la imagen, el ministro de Informaci├│n y Turismo, Manuel Fraga Iribarne camino de rendir pleites├¡a a la Virgen del Pilar. Luego negociar├¡a con el Arzobispado el dinero p├║blico a transferir a las arcas del Cabildo para fomento del turismo religioso en la ciudad. Al fondo, la plaza de La Seo.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65572700, -0.87751100, '0101000020E61000000F2BDCF29114ECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15382864195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15382864195.webp', 'https://www.flickr.com/photos/zaragozaantigua/15382864195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23817, 'Casa de Torrellas 1844', '"Patio del Comercio". Saliendo de la calle de Santiago y llegando a la del Horno de la Yedra, se llegaba a la antigua casa de Torrellas, llamada luego del Comercio, si bien su propiedad era del marqu├®s de Ayerbe. Su patio en tres alturas soportadas sobre seis columnas era todo un monumento g├│tico-plateresco sin igual en la ciudad, del que tampoco desmerec├¡an los artesonados de madera. Con la apertura de la nueva calle de Alfonso I, en la d├®cada de los 60 del siglo XIX, la manzana en la que se asentaba esta joya fue arrasada, y se levantaron nuevas estructuras adaptadas al nuevo planeamiento de la zona. Algunos restos de este patio, descontextualizados, fueron reutilizados en el palacio que los marqueses de Ayerbe ten├¡an en la cercana calle del Pilar, cayendo por segunda vez cuando el edificio fue expropiado para construir el actual edificio del Ayuntamiento. Este segundo episodio de extinci├│n termin├│ con los restos de la casa de Torrellas. Fuente visual: "Recuerdos y Bellezas de Espa├▒a. Obra destinada a dar a conocer sus monumentos, antig├╝edades y vistas pintorescas en l├íminas dibujadas del natural y litografiadas por F. J. Parcerisa, acompa├▒adas de texto por P. Piferrer y J. M. Quadrado. Arag├│n: Jos├® Mar├¡a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65580700, -0.87892700, '0101000020E6100000D84812842B20ECBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18351577309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18351577309.webp', 'https://www.flickr.com/photos/zaragozaantigua/18351577309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
